import { Box, Stack } from "@mui/material";
import dayjs from "dayjs";
import { useMemo } from "react";

import { useGetClientSettings } from "@dfp/bw-react-client-settings";
import { EmptyState } from "@dfp/react-components";
import { IconAlertCircle, IconBarChart03 } from "@dfp/react-icons";

import { useGetCashFlowAndBalanceStates } from "../queries/index.ts";
import { useTT } from "../useTT.ts";
import { CashflowTableSection } from "./CashflowTableSection.tsx";
import { useCockpit } from "./CockpitContext.tsx";
import { CurrentBalanceChartSection } from "./CurrentBalanceChartSection.tsx";
import { HealthIndicatorsSection } from "./HealthIndicatorsSection.tsx";
import { SelectionProvider } from "./SelectionContext.tsx";
import { TimePeriodProvider } from "./TimePeriodContext.tsx";
import { cashflowLayoutConfig } from "./cashflow-layout.config.ts";
import { CashflowTableProvider } from "./cashflow-table/index.ts";
import { CashflowChartProvider } from "./chart/index.ts";
import {
  useCashflowLayoutConfig,
  useCashflowTimePeriodFilter,
  useCategoryFilter,
} from "./hooks/index.ts";
import {
  findColumnIndexForDate,
  getClientSettings,
  mapCategoryFilterToParam,
} from "./utils/index.ts";

type CashflowTabProps = {
  companyId: string;
};

export function CashflowTab({ companyId }: CashflowTabProps) {
  const { tt } = useTT();
  const { companySettings } = useCockpit();
  const clientSettings = useGetClientSettings({
    companyId,
    options: { select: getClientSettings },
  });
  const currency =
    companySettings?.currency ?? clientSettings.data?.currency ?? "EUR";
  const bankAccountIdArray = clientSettings.data?.bankAccountIdArray ?? [];

  const { tableContainerRef, columnCount } = useCashflowLayoutConfig();

  const { dateFrom, dateTo, interval, setInterval, ...timePeriodControls } =
    useCashflowTimePeriodFilter({
      columnCount,
      maxDateRangeFrom: clientSettings.data?.maxDateRangeFrom,
      // WARN: Do not remove: CAS-839
      // maxDateRangeTo: clientSettings.data?.maxDateRangeTo,
      maxDateRangeTo: dayjs().format("YYYY-MM-DD"),
      companyId,
    });

  const categoryFilterState = useCategoryFilter();
  const { categoryFilter, allCategoryValues } = categoryFilterState;

  const {
    data,
    isPending: isCashflowPending,
    isFetching,
    isPlaceholderData: isCashflowPlaceholder,
    error,
  } = useGetCashFlowAndBalanceStates({
    params: {
      dateFrom,
      dateTo,
      currency,
      bankAccountIdArray,
      sumAggregationIntervalGranularity: interval,
      category: mapCategoryFilterToParam(categoryFilter, allCategoryValues),
    },
  });

  // Cached data for the active key should render immediately. Only show loading
  // states when the active key has no cached payload yet and React Query is still
  // serving placeholder data from the previous selection.
  const isInitialLoading = clientSettings.isPending || isCashflowPending;
  const isFilterTransitionLoading =
    !isInitialLoading && isCashflowPlaceholder && isFetching;
  const isTableLoading = isInitialLoading || isFilterTransitionLoading;

  const selectedColumn = useMemo(
    () =>
      data?.cashFlowStates?.sumArray
        ? findColumnIndexForDate(
            data.cashFlowStates.sumArray,
            timePeriodControls.selectedDay,
          )
        : null,
    [data?.cashFlowStates?.sumArray, timePeriodControls.selectedDay],
  );

  if (error) {
    return (
      <EmptyState
        title={tt("error.title")}
        subtitle={error.message || tt("error.generic")}
        icon={<IconAlertCircle />}
      />
    );
  }

  if (
    !(isInitialLoading || isFilterTransitionLoading) &&
    (!data || (data.cashFlowStates?.sumArray?.length ?? 0) === 0)
  ) {
    return (
      <EmptyState
        icon={<IconBarChart03 />}
        title={tt("chart.noData")}
        subtitle={tt("chart.noDataDescription")}
      />
    );
  }

  return (
    <Stack sx={{ gap: 2 }}>
      <SelectionProvider selectedColumn={selectedColumn}>
        <TimePeriodProvider timePeriodControls={timePeriodControls}>
          {/* Upper Section - Health Indicators + Chart */}
          <Box
            sx={{
              display: "grid",
              gridTemplateColumns: {
                xs: "1fr",
                md: `${cashflowLayoutConfig.labelColumnWidth - cashflowLayoutConfig.yAxisWidth}px 1fr`,
              },
            }}
          >
            <HealthIndicatorsSection />
            <CashflowChartProvider
              data={data}
              interval={interval}
              setInterval={setInterval}
              currency={currency}
              bankAccountCount={bankAccountIdArray.length}
            >
              <CurrentBalanceChartSection
                isInitialLoading={isInitialLoading}
                isRefetching={isFilterTransitionLoading}
              />
            </CashflowChartProvider>
          </Box>

          {/* Bottom Section - Table */}
          <Box ref={tableContainerRef}>
            <CashflowTableProvider
              data={data}
              interval={interval}
              currency={currency}
              bankAccountIdArray={bankAccountIdArray}
              categoryFilterState={categoryFilterState}
            >
              <CashflowTableSection isLoading={isTableLoading} />
            </CashflowTableProvider>
          </Box>
        </TimePeriodProvider>
      </SelectionProvider>
    </Stack>
  );
}

import type { Dayjs } from "dayjs";

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

import type { Interval } from "../utils/formatPeriodLabel.ts";

/**
 * Chart view modes for the cashflow visualization
 * - bar: Bar chart showing income vs costs
 * - line: Line chart showing balance progression
 */
export type ChartViewMode = "bar" | "line";

export type { Interval };

export type Currency = NonNullable<
  BwCashflowModel["getCashFlowAndBalanceStates"]["request"]["filtering"]["currency"]
>;

/**
 * Category sum for income or costs
 */
export type CategorySum = {
  category: string;
  amount: number;
};

/**
 * Balance state object from API
 */
export interface BalanceState {
  balance: number;
  date?: string;
}

/**
 * Cash flow interval from API response
 */
export type CashFlowInterval = {
  dateFrom: string;
  dateTo: string;
  costs: number;
  income: number;
  netChange: number;
  startedBalance?: BalanceState;
  finalBalance?: BalanceState;
  incomeCategorySum?: CategorySum[];
  costsCategorySum?: CategorySum[];
  transactionCount?: number;
  cumulativeCosts?: number;
  cumulativeIncome?: number;
  cumulativeNetChange?: number;
};

/**
 * Balance quality indicator
 */
export type BalanceQuality = "IMPORTED" | "DERIVED" | "CALCULATED";

/**
 * Balance point from API response
 */
export type BalancePoint = {
  balance: number;
  date?: string;
  balanceQuality?: BalanceQuality;
};

/**
 * Transformed data point for bar chart visualization
 */
export type BarChartDataPoint = {
  // Display label for the period
  period: string;
  // Unique identifier for synchronization (e.g., "2025-01-01_2025-01-31")
  periodKey: string;
  dateFrom: string;
  dateTo: string;
  income: number;
  costs: number;
  netChange: number;
  incomePlanned?: number;
  costsPlanned?: number;
  incomeCategories?: CategorySum[];
  costsCategories?: CategorySum[];
  transactionCount?: number;
};

/**
 * Transformed data point for line chart visualization
 */
export type LineChartDataPoint = {
  [key: string]: number | string | undefined;
  // ISO date string
  date: string;
  // Numeric timestamp for proper x-axis spacing
  timestamp: number;
  dateLabel: string;
  balance: number;
  // Link to corresponding bar chart period for synchronization
  periodKey: string;
  balanceQuality: BalanceQuality;
};

/**
 * Legend data for displaying current balance and account info
 */
export type LegendData = {
  /** Current total balance across all selected accounts */
  currentBalance: number | null;
  /** Currency code (e.g., "EUR", "CZK") */
  currency: string;
  /** Number of bank accounts included in the data */
  bankAccountCount: number;
  /** Quality of the most recent balance point */
  balanceQuality?: BalanceQuality;
};

/**
 * Time period controls for navigating and selecting periods
 */
export type TimePeriodControlsType = {
  /** Currently selected day that determines the highlighted period */
  selectedDay: Dayjs;
  /** Select a specific day (from date picker). Optionally update interval atomically. */
  setPeriod: (day: Dayjs, newInterval?: Interval) => void;
  /** Navigate to previous period */
  goToPreviousPeriod: () => void;
  /** Navigate to next period */
  goToNextPeriod: () => void;
  /** Whether we can navigate to previous period (not at min date) */
  canGoToPreviousPeriod: boolean;
  /** Whether we can navigate to next period (not at max date) */
  canGoToNextPeriod: boolean;
  /** Minimum selectable date (from settings - oldest transaction) */
  maxDateRangeFrom: Dayjs;
  /** Maximum selectable date (current date + 5 months) */
  maxDateRangeTo: Dayjs;
};

/**
 * Context type for cashflow chart state and data
 */
export type CashflowChartContextType = {
  viewMode: ChartViewMode;
  setViewMode: (mode: ChartViewMode) => void;
  interval: Interval;
  setInterval: (interval: Interval) => void;
  barChartData: BarChartDataPoint[];
  lineChartData: LineChartDataPoint[];
  lineChartSegmentKeys: {
    calculatedSegmentKeys: string[];
    importedSegmentKeys: string[];
    derivedSegmentKeys: string[];
  };
  legendData: LegendData;
};

import { type ReactNode, useMemo, useState } from "react";

import type {
  BalancePoint,
  CashFlowInterval,
  CashflowChartContextType,
  ChartViewMode,
  Interval,
  LegendData,
} from "../../types/cashflow.types.ts";
import {
  transformToBarChartData,
  transformToLineChartData,
} from "../../utils/index.ts";
import { segmentLineChartQuality } from "../line-chart/index.ts";
import {
  CashflowChartContext,
  useCashflowChartContext,
} from "./cashflowChart.context.ts";

type CashflowChartProviderProps = {
  children: ReactNode;
  data?: {
    cashFlowStates?: {
      sumArray?: CashFlowInterval[];
    };
    aggregatedBalanceValues?: Record<string, BalancePoint> | BalancePoint[];
  };
  // Interval state from parent (where the query is made)
  interval: Interval;
  setInterval: (interval: Interval) => void;
  /** Currency code for display (e.g., "EUR", "CZK") */
  currency: string;
  /** Number of bank accounts included in the query */
  bankAccountCount: number;
};

/**
 * Provider component for cashflow chart context
 * Manages view state, selection, and data transformations
 */
export function CashflowChartProvider({
  children,
  data,
  interval,
  setInterval,
  currency,
  bankAccountCount,
}: CashflowChartProviderProps) {
  const [viewMode, setViewMode] = useState<ChartViewMode>("bar");

  const cashFlowData = useMemo(
    () => data?.cashFlowStates?.sumArray || [],
    [data],
  );

  const balanceData = useMemo(() => {
    const rawBalanceData = data?.aggregatedBalanceValues;

    if (!rawBalanceData) {
      return {};
    }

    if (!Array.isArray(rawBalanceData)) {
      return rawBalanceData;
    }

    return rawBalanceData.reduce(
      (acc, balancePoint) => {
        if (balancePoint.date) {
          acc[balancePoint.date] = balancePoint;
        }
        return acc;
      },
      {} as Record<string, BalancePoint>,
    );
  }, [data]);

  const barChartData = useMemo(
    () => transformToBarChartData(cashFlowData, interval),
    [cashFlowData, interval],
  );

  const lineChartData = useMemo(
    () => transformToLineChartData(balanceData, cashFlowData),
    [balanceData, cashFlowData],
  );

  const segmentationResult = useMemo(
    () => segmentLineChartQuality(lineChartData),
    [lineChartData],
  );

  // Compute current balance from the latest balance point
  const legendData = useMemo<LegendData>(() => {
    // Get the latest balance from aggregatedBalanceValues
    const balanceEntries = Object.entries(balanceData);
    if (balanceEntries.length === 0) {
      return { currentBalance: null, currency, bankAccountCount };
    }

    // Sort by date descending to get the most recent balance
    const sortedEntries = balanceEntries.sort(([dateA], [dateB]) =>
      dateB.localeCompare(dateA),
    );
    const latestPoint = sortedEntries[0]?.[1];
    const latestBalance = latestPoint?.balance ?? null;
    const balanceQuality = latestPoint?.balanceQuality;

    return {
      currentBalance: latestBalance,
      currency,
      bankAccountCount,
      balanceQuality,
    };
  }, [balanceData, currency, bankAccountCount]);

  const contextValue = useMemo<CashflowChartContextType>(
    () => ({
      viewMode,
      setViewMode,
      interval,
      setInterval,
      legendData,
      barChartData,
      lineChartData: segmentationResult.chartData,
      lineChartSegmentKeys: {
        calculatedSegmentKeys: segmentationResult.calculatedSegmentKeys,
        importedSegmentKeys: segmentationResult.importedSegmentKeys,
        derivedSegmentKeys: segmentationResult.derivedSegmentKeys,
      },
    }),
    [
      viewMode,
      interval,
      setInterval,
      barChartData,
      segmentationResult,
      legendData,
    ],
  );

  return (
    <CashflowChartContext.Provider value={contextValue}>
      {children}
    </CashflowChartContext.Provider>
  );
}

