};

export function CashflowTableProvider({
  children,
  data,
  interval,
  currency,
  bankAccountIdArray,
  categoryFilterState,
}: CashflowTableProviderProps) {
  const tableData = useMemo(() => {
    if (!data) {
      return null;
    }
    return transformCashflowData(data);
  }, [data]);

  const context = useMemo(
    () => ({
      data: tableData,
      interval,
      currency,
      bankAccountIdArray,
      ...categoryFilterState,
    }),
    [tableData, interval, currency, bankAccountIdArray, categoryFilterState],
  );

  return (
    <CashflowTableContext.Provider value={context}>
      {children}
    </CashflowTableContext.Provider>
  );
}

import { GetClientSettingsResponse } from "@dfp/bw-react-client-settings";

export type ClientSettingsDocumentMeta = {
  documentId: string;
};

export function getSelectedAccounts(data: GetClientSettingsResponse) {
  const firstDoc = data?.documentList?.[0];

  const meta = {
    documentId: firstDoc?.documentHeader.id ?? "",
  } satisfies ClientSettingsDocumentMeta;

  const accountIds =
    firstDoc?.cashFlowSettings?.entityData?.selectedBankAccountRefArray
      .map((ref) => ref.documentId)
      .filter((id): id is string => !!id) ?? [];

  return {
    currency: firstDoc?.currencySettings?.entityData.currency,
    accountIds,
    meta,
  };
}

export function getClientSettings(
  clientSettingsData: GetClientSettingsResponse,
) {
  const documentItem = clientSettingsData?.documentList?.[0];
  const currency = documentItem?.currencySettings?.entityData.currency ?? "CZK";
  const bankAccountIdArray =
    documentItem?.cashFlowSettings?.entityData?.selectedBankAccountRefArray
      .map((ref) => ref.documentId)
      .filter((id): id is string => !!id) ?? [];

  // maxDateRangeFrom comes from BE - min(transaction date) across all selected accounts
  const maxDateRangeFrom =
    documentItem?.virtualCalendarPropertiesData?.entityData?.maxDateRangeFrom;
  const maxDateRangeTo =
    documentItem?.virtualCalendarPropertiesData?.entityData?.maxDateRangeTo;
  return {
    currency,
    bankAccountIdArray,
    maxDateRangeFrom,
    maxDateRangeTo,
  };
}

