import { Stack, Typography, useTheme } from "@mui/material";
import { ComponentProps } from "react";

import {
  ChartTooltip,
  ChartTooltipContent,
  ChartTooltipHeader,
} from "@dfp/react-chart";
import { CurrencyAmount } from "@dfp/react-currency-amount";
import { IconAlertSquare, IconAlertTriangle } from "@dfp/react-icons";

import { useTT } from "../../../useTT.ts";
import type { LineChartDataPoint } from "../../types/cashflow.types.ts";
import { getQualityThemeColor } from "../cashflowQuality.config.ts";

type ChartTooltipContentArgs = ComponentProps<
  typeof ChartTooltipContent<string, LineChartDataPoint>
>;

type Props = ChartTooltipContentArgs & {
  labelFormatter: (label: string | number | undefined) => string;
  currency: string;
  active: boolean;
};

const QUALITY_PREFIX: Record<LineChartDataPoint["balanceQuality"], string> = {
  CALCULATED: "calculated",
  IMPORTED: "imported",
  DERIVED: "derived",
};

const ICON_SIZE = 18;

/**
 * Custom tooltip for CashflowLineChart that shows exactly one balance row
 * at bridge points where two quality segments share a data point.
 *
 * At a bridge point, multiple series have values (the outgoing segment's real
 * value and the incoming segment's copied bridge value). Without filtering,
 * both rows would appear in the tooltip. This component keeps only the entry
 * whose dataKey prefix matches the data point's own balanceQuality, so the
 * user always sees a single, accurate row.
 */
export function CashflowLineChartTooltip({
  active,
  payload,
  label,
  labelFormatter,
  currency,
}: Props) {
  const { tt } = useTT();
  const theme = useTheme();
  const point = payload[0]?.payload;

  if (!active || !payload.length || !point) return null;

  const prefix = QUALITY_PREFIX[point.balanceQuality];
  const filteredPayload = payload.filter(
    (entry) =>
      typeof entry.dataKey === "string" && entry.dataKey.startsWith(prefix),
  );
  const displayPayload =
    filteredPayload.length > 0 ? filteredPayload : payload.slice(0, 1);

  const { balanceQuality } = point;
  const qualityColor =
    balanceQuality !== "IMPORTED"
      ? getQualityThemeColor(theme, balanceQuality)
      : undefined;

  const qualityTitle =
    balanceQuality === "DERIVED"
      ? tt("chart.inaccurateFinalBalance")
      : balanceQuality === "CALCULATED"
        ? tt("chart.calculatedFinalBalance")
        : tt("chart.endingBalance");

  const icon =
    balanceQuality === "DERIVED" ? (
      <IconAlertTriangle width={ICON_SIZE} height={ICON_SIZE} />
    ) : balanceQuality === "CALCULATED" ? (
      <IconAlertSquare width={ICON_SIZE} height={ICON_SIZE} />
    ) : null;

  const value = displayPayload[0]?.value;

  return (
    <ChartTooltip>
      <ChartTooltipHeader
        sx={{
          flexDirection: "column",
          alignItems: "stretch",
          justifyContent: "flex-start",
          gap: 0.5,
        }}
      >
        <Stack
          sx={{
            flexDirection: "row",
            alignItems: "center",
            gap: 0.5,
            color: qualityColor,
          }}
        >
          {icon}
          <Typography variant="subtitle2" sx={{ color: "inherit" }}>
            {qualityTitle}
          </Typography>
        </Stack>
        <Stack
          sx={{
            flexDirection: "row",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <Typography variant="body2">{labelFormatter(label)}</Typography>
          <Typography variant="subtitle2">
            <CurrencyAmount
              value={Number(value ?? 0)}
              currency={currency}
              naturalPrecision
            />
          </Typography>
        </Stack>
      </ChartTooltipHeader>
    </ChartTooltip>
  );
}

import { useTheme } from "@mui/material";
import dayjs from "dayjs";
import { useMemo } from "react";

import { createChart } from "@dfp/react-chart";

import { useTT } from "../../../useTT.ts";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";
import { LineChartDataPoint } from "../../types/cashflow.types.ts";
import { formatCashflowAmount, formatDateToISO } from "../../utils/index.ts";
import { useCashflowChartContext } from "../cashflow-chart/index.ts";
import { getQualityThemeColor } from "../cashflowQuality.config.ts";
import { CashflowLegend } from "../components/index.ts";
import { CHART_HEIGHT } from "../constants/index.ts";
import { CashflowLineChartTooltip } from "./CashflowLineChartTooltip.tsx";

const Chart = createChart<LineChartDataPoint>();

/**
 * Area line chart displaying account balance progression over time.
 *
 * Reads data from `CashflowChartContext` and renders three visually distinct
 * segment types based on balance quality:
 * - **CALCULATED** — solid line, info color
 * - **IMPORTED** — solid line, primary color
 * - **DERIVED** — dashed line, warning color
 */
export function CashflowLineChart() {
  const { tt, language } = useTT();
  const theme = useTheme();
  const {
    lineChartData,
    lineChartSegmentKeys,
    barChartData,
    interval,
    legendData,
  } = useCashflowChartContext();
  const { calculatedSegmentKeys, importedSegmentKeys, derivedSegmentKeys } =
    lineChartSegmentKeys;

  const periodTicks = useMemo(
    () =>
      interval === "1M"
        ? barChartData.map((p) => dayjs(p.dateTo).valueOf())
        : barChartData.flatMap((p) => [
            dayjs(p.dateFrom).valueOf(),
            dayjs(p.dateTo).valueOf(),
          ]),
    [barChartData, interval],
  );

  const periodTickLabelMap = useMemo(
    () =>
      new Map(
        interval === "1M"
          ? barChartData.map((p) => [
              dayjs(p.dateTo).valueOf(),
              dayjs(p.dateTo).format("D MMM 'YY"),
            ])
          : barChartData.flatMap((p) => [
              [
                dayjs(p.dateFrom).valueOf(),
                dayjs(p.dateFrom).format("D MMM 'YY"),
              ],
              [dayjs(p.dateTo).valueOf(), dayjs(p.dateTo).format("D MMM 'YY")],
            ]),
      ),
    [barChartData, interval],
  );

  const xAxisFormatter = (timestamp: number) =>
    periodTickLabelMap.get(timestamp) ?? "";

  const labelFormatter = (label: string | number | undefined) => {
    const timestamp = typeof label === "number" ? label : Number(label ?? 0);
    const dataPoint = lineChartData.find((d) => d.timestamp === timestamp);
    return dayjs(dataPoint?.date).format("D MMM 'YY") || "";
  };

  const referenceLinePosition = useMemo(() => {
    const todayStr = formatDateToISO(dayjs());
    return dayjs(todayStr).valueOf();
  }, []);

  const chartConfig = useMemo(
    () => ({
      ...Object.fromEntries(
        calculatedSegmentKeys.map((key) => [
          key,
          {
            label: tt("chart.calculated"),
            color: getQualityThemeColor(theme, "CALCULATED"),
          },
        ]),
      ),
      ...Object.fromEntries(
        importedSegmentKeys.map((key) => [
          key,
          {
            label: tt("chart.imported"),
            color: getQualityThemeColor(theme, "IMPORTED"),
          },
        ]),
      ),
      ...Object.fromEntries(
        derivedSegmentKeys.map((key) => [
          key,
          {
            label: tt("chart.derived"),
            color: getQualityThemeColor(theme, "DERIVED"),
          },
        ]),
      ),
    }),
    [calculatedSegmentKeys, importedSegmentKeys, derivedSegmentKeys, theme, tt],
  );

  return (
    <Chart.Container config={chartConfig} height={CHART_HEIGHT}>
      <Chart.AreaChart data={lineChartData}>
        <Chart.CartesianGrid />
        <Chart.XAxis
          dataKey="timestamp"
          tickFormatter={xAxisFormatter}
          ticks={periodTicks}
          padding={{ right: 24 }}
        />
        <Chart.YAxis
          width={cashflowLayoutConfig.yAxisWidth}
          tickFormatter={(val) => formatCashflowAmount(val, language)}
          domain={[
            (dataMin: number) => Math.floor(dataMin * 0.95),
            (dataMax: number) => Math.ceil(dataMax * 1.05),
          ]}
        />

        <Chart.Tooltip
          cursor={{ stroke: theme.palette.custom.fillError }}
          content={({ active, payload, label }) => (
            <CashflowLineChartTooltip
              active={active ?? false}
              payload={payload ?? []}
              label={label}
              labelFormatter={labelFormatter}
              currency={legendData.currency}
            />
          )}
        />

        <Chart.Legend
          content={({ payload }) => <CashflowLegend payload={payload} />}
        />

        <Chart.ReferenceLine x={referenceLinePosition} />

        {calculatedSegmentKeys.map((key) => (
          <Chart.Area
            key={key}
            type="bumpX"
            dataKey={key}
            strokeDasharray="8 8"
            connectNulls={false}
          />
        ))}
        {importedSegmentKeys.map((key) => (
          <Chart.Area
            key={key}
            type="bumpX"
            dataKey={key}
            connectNulls={false}
          />
        ))}
        {derivedSegmentKeys.map((key) => (
          <Chart.Area
            key={key}
            type="bumpX"
            dataKey={key}
            strokeDasharray="5 5"
            connectNulls={false}
          />
        ))}
      </Chart.AreaChart>
    </Chart.Container>
  );
}

