export function CashflowBarChart() {
  const { tt, language } = useTT();
  const theme = useTheme();
  const { barChartData, legendData } = useCashflowChartContext();
  const selectedColumn = useSelectedColumn();
  const { setPeriod } = useTimePeriodControls();
  const selectedPeriod =
    selectedColumn != null ? barChartData[selectedColumn]?.period : undefined;

  const referenceLinePosition = useMemo(() => {
    const todayStr = formatDateToISO(dayjs());

    return barChartData.find((item) => {
      const today = dayjs(todayStr);
      const from = dayjs(item.dateFrom);
      const to = dayjs(item.dateTo);
      return (
        (today.isAfter(from) || today.isSame(from)) &&
        (today.isBefore(to) || today.isSame(to))
      );
    })?.period;
  }, [barChartData]);

  const handleBarClick = (e: MouseHandlerDataParam) => {
    const rawIndex = e.activeTooltipIndex;
    const index = rawIndex != null ? Number(rawIndex) : null;
    const validIndex = Number.isNaN(index) ? null : index;

    if (validIndex !== null) {
      const dateFrom = barChartData[validIndex]?.dateFrom;
      if (dateFrom) {
        setPeriod(dayjs(dateFrom));
      }
    }
  };

  return (
    <Chart.Container
      config={{
        income: {
          label: tt("chart.income"),
          color: theme.palette.custom.fillSuccess,
        },
        costs: {
          label: tt("chart.costs"),
          color: theme.palette.custom.fillError,
        },
      }}
      height={CHART_HEIGHT}
    >
      <Chart.BarChart data={barChartData} barGap={2} onClick={handleBarClick}>
        <Chart.CartesianGrid />
        <Chart.XAxis dataKey="period" />
        <Chart.YAxis
          width={cashflowLayoutConfig.yAxisWidth}
          tickFormatter={(val) => formatCashflowAmount(val, language)}
        />

        <Chart.Tooltip
          // we are using custom ReferenceArea, so we can control "highlighting" manually
          cursor={false}
          header={{ title: tt("chart.past") }}
          formatter={(value) =>
            formatCurrencyAmount({
              value: Number(value ?? 0),
              currency: legendData.currency,
              language,
            })
          }
        />
        {selectedColumn !== null && (
          <ReferenceArea
            x1={selectedPeriod}
            x2={selectedPeriod}
            fill={theme.palette.custom.fill}
            fillOpacity={0.2}
          />
        )}

        <Chart.Legend
          content={({ payload }) => <CashflowLegend payload={payload} />}
        />

        <Chart.ReferenceLine x={referenceLinePosition} />

        <Chart.Bar dataKey="income" />
        <Chart.Bar dataKey="costs" />
      </Chart.BarChart>
    </Chart.Container>
  );
}

import { Popover } from "@mui/material";
import { useCallback, useEffect, useMemo, useState } from "react";

import { useCompanyContext } from "@dfp/bw-react-user-context";
import { AppDialogCloseButton } from "@dfp/react-components";

import { CategoryDetail } from "../../../categoryDetail/index.ts";
import { useCashflowTable } from "../CashflowTableContext.tsx";
import type { CategoryDetailPanelParams } from "./categoryDetailPanel.context.ts";

type CategoryDetailPopoverProps = {
  anchorPosition: { left: number; top: number };
  onChangeColumn: (index: number) => void;
  onClose: () => void;
  open: boolean;
  params: CategoryDetailPanelParams | null;
};

export function CategoryDetailPopover({
  anchorPosition,
  onChangeColumn,
  onClose,
  open,
  params,
}: CategoryDetailPopoverProps) {
  const { bankAccountIdArray, currency, data, interval } = useCashflowTable();
  const { companyId } = useCompanyContext();

  const [currentIndex, setCurrentIndex] = useState(params?.columnIndex ?? 0);

  useEffect(() => {
    if (params) setCurrentIndex(params.columnIndex);
  }, [params]);

  const periods = data?.periods;
  const period = periods?.[currentIndex];

  const handleNavigate = useCallback(
    (newIndex: number) => {
      setCurrentIndex(newIndex);
      onChangeColumn(newIndex);
    },
    [onChangeColumn],
  );

  const paid = useMemo(() => {
    if (!period || !params) return 0;

    const categoriesMap =
      params.direction === "IN"
        ? period.incomeCategories
        : period.costsCategories;

    return categoriesMap?.get(params.category) ?? 0;
  }, [period, params]);

  return (
    <Popover
      anchorPosition={anchorPosition}
      anchorReference="anchorPosition"
      disableScrollLock
      onClose={onClose}
      open={open}
      sx={{ zIndex: (theme) => theme.zIndex.drawer }}
      slotProps={{
        paper: {
          sx: {
            borderRadius: (theme) => theme.borderRadius.md,
            maxWidth: 730,
            position: "relative",
            px: 3,
            width: 730,
          },
        },
      }}
      transformOrigin={{ horizontal: "right", vertical: "top" }}
    >
      <AppDialogCloseButton onClose={onClose} />

      {params && period && (
        <CategoryDetail
          bankAccountIdArray={bankAccountIdArray}
          categoryId={params.category}
          categoryLabel={params.categoryLabel}
          companyId={companyId}
          currency={currency}
          dateFrom={period.dateFrom}
          dateTo={period.dateTo}
          direction={params.direction}
          forecasted={0}
          interval={interval}
          key={`${params.category}-${params.direction}-${params.columnIndex}`}
          onNextPeriod={
            periods && currentIndex < periods.length - 1
              ? () => handleNavigate(currentIndex + 1)
              : undefined
          }
          onPreviousPeriod={
            currentIndex > 0
              ? () => handleNavigate(currentIndex - 1)
              : undefined
          }
          paid={paid}
        />
      )}
    </Popover>
  );
}

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

export type CashFlowResponse =
  BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
type CashFlowStates = NonNullable<CashFlowResponse["cashFlowStates"]>;
type SumArray = NonNullable<CashFlowStates["sumArray"]>;
type SumArrayItem = SumArray[number];
type IncomeCategorySum = NonNullable<SumArrayItem["incomeCategorySum"]>;
type ApiCategoryType = IncomeCategorySum[number]["category"];

export type CategoryType = ApiCategoryType;

/**
 * Represents a single period column in the cashflow table
 */
export type CashflowPeriod = {
  id: string;
  /** Date of the period (YYYY-MM-DD) */
  dateFrom: string;
  dateTo: string;
  /** Balance at the start of this period */
  startingBalance: number;
  /** Total income for this period */
  income: number;
  /** Total costs for this period */
  costs: number;
  /** Net change (income - costs) */
  netBalance: number;
  /** Final balance at end of period (startingBalance + netBalance) */
  finalBalance: number;
  incomeCategories: Map<CategoryType, number>;
  costsCategories: Map<CategoryType, number>;
  progressPercentage?: number;
  transactionCount?: number;
};

/**
 * Complete data structure for the cashflow table
 */
export type CashflowTableData = {
  periods: CashflowPeriod[];
  granularity: "1D" | "1W" | "1M";
  categories: {
    income: CategoryType[];
    costs: CategoryType[];
  };
};

export type CategoryFilter = {
  income: CategoryType[];
  costs: CategoryType[];
};

export type CategoryFilterSection = "income" | "costs";

export type CategoryOption = {
  value: CategoryType;
  label: string;
};

export type CategoryFilterState = {
  categoryFilter: CategoryFilter;
  setCategoryFilter: (filter: CategoryFilter) => void;
  allCategories: CategoryOption[];
  allCategoryValues: CategoryType[];
  isFiltered: boolean;
  totalSelected: number;
  totalAvailable: number;
};

export type CashflowTableCellProps = {
  value: number;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  /** Optional progress percentage to display as a bar */
  progressPercentage?: number;
  /** Color mode for value display:
   * - "balance": red for negative, green for positive (Starting Balance, Net Balance)
   * - "final": red for negative only, neutral for positive/zero (Final Balance)
   * - "none": always neutral color (Income, Costs, all categories)
   * Default: "none"
   */
  colorMode?: "balance" | "final" | "none";
  /** Optional click handler. When provided, replaces the default column toggle behavior. */
  onClick?: () => void;
};

