                  <CurrencyRadioItem
                    key={currency}
                    currency={currency}
                    label={getItemLabel(currency)}
                    value={currency}
                    isSelected={field.state.value === currency}
                  />
                ))}
              </Stack>
            </RadioGroup>
          )}
        </form.AppField>
      </Stack>
    );
  },
});

