import { useMemo } from "react";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";
import type {
  TableColumnSettings,
  TableRowSettings,
} from "@dfp/react-components";

import { useTT } from "../../../useTT.ts";
import type { CategoryTransaction } from "../categoryDetail.types.ts";
import { ColumnAmount } from "./ColumnAmount.tsx";
import { ColumnDate } from "./ColumnDate.tsx";
import { ColumnMethod } from "./ColumnMethod.tsx";
import { ColumnSenderOrRecipient } from "./ColumnSenderOrRecipient.tsx";

type Params = {
  direction: TransactionDirection;
  currency: string;
};

type CategoryTransactionColumnId =
  | "amount"
  | "date"
  | "method"
  | "senderOrRecipient";

export function useCategoryTransactionRowSettings({
  direction,
  currency,
}: Params): TableRowSettings<CategoryTransaction> {
  const { tt } = useTT();
  return useMemo(() => {
    const senderLabel =
      direction === "IN"
        ? tt("categoryDetail.transactionsTable.sender")
        : tt("categoryDetail.transactionsTable.recipient");

    const fallbackLabel = tt("categoryDetail.notAvailable");

    const columns: ReadonlyArray<
      TableColumnSettings<CategoryTransaction> & {
        id: CategoryTransactionColumnId;
      }
    > = [
      {
        id: "date",
        label: tt("categoryDetail.transactionsTable.date"),
        sortKey: "displayDate",
        width: "13%",
        getValue: (tx) => <ColumnDate transaction={tx} />,
      },
      {
        id: "senderOrRecipient",
        label: senderLabel,
        sortKey: "counterBankAccountName",
        width: "34%",
        getValue: (tx) => (
          <ColumnSenderOrRecipient
            transaction={tx}
            fallbackLabel={fallbackLabel}
          />
        ),
      },
      {
        id: "method",
        label: tt("categoryDetail.transactionsTable.method"),
        width: "26%",
        getValue: (tx) => (
          <ColumnMethod direction={direction} transaction={tx} />
        ),
      },
      {
        id: "amount",
        label: tt("categoryDetail.transactionsTable.amount"),
        sortKey: `amount${currency}`,
        width: "27%",
        align: "right",
        getValue: (tx) => (
          <ColumnAmount
            transaction={tx}
            currency={currency}
            direction={direction}
          />
        ),
      },
    ] as const;

    return {
      getId: (tx) => tx.id,
      columns: columns as Array<TableColumnSettings<CategoryTransaction>>,
    };
  }, [tt, direction, currency]);
}

import type { SxProps, Theme } from "@mui/material";
import { Box, Stack, TableCell, TableRow, Typography } from "@mui/material";
import { useMemo } from "react";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";
import { InfiniteList, type SortOrder } from "@dfp/react-components";
import { DocumentListTable } from "@dfp/react-document-list-table";

import { useTT } from "../../../useTT.ts";
import type {
  CategorySorting,
  CategoryTransaction,
} from "../categoryDetail.types.ts";
import { LoadingMoreSkeleton } from "./LoadingMoreSkeleton.tsx";
import { TransactionsTableEmptyState } from "./TransactionsTableEmptyState.tsx";
import { BORDERED_CONTAINER_SX } from "./transactionsTable.styles.ts";
import { useCategoryTransactionRowSettings } from "./useCategoryTransactionRowSettings.tsx";

/**
 * Border + border-radius live on this Box (the scroll container).
 * Combined with `overflow: auto` (from the `sx` prop), the Box clips content
 * at rounded corners while allowing `position: sticky` on `<thead>`.
 *
 * Paper and TableContainer need `overflow: visible` so they don't block sticky.
 */
const TABLE_WRAPPER_SX = {
  ...BORDERED_CONTAINER_SX,
  "& .MuiPaper-root": {
    boxShadow: "none",
    overflow: "visible",
  },
  "& .MuiTableContainer-root": {
    overflow: "visible",
  },
  "& table": {
    tableLayout: "fixed",
  },
  "& thead": {
    position: "sticky",
    top: 0,
    zIndex: 1,
    "& th": {
      backgroundColor: "background.paper",
    },
  },
} as const;

type Props = {
  direction: TransactionDirection;
  currency: string;
  transactions: ReadonlyArray<CategoryTransaction>;
  sorting: CategorySorting;
  onSortChange: (sortingAttribute: string, order: SortOrder) => void;
  onRowClick?: (transaction: CategoryTransaction) => void;
  error: Error | null;
  isLoading?: boolean;
  fetchNextPage: (() => void) | undefined;
  hasNextPage?: boolean;
  isFetchingNextPage?: boolean;
  sx?: SxProps<Theme>;
};

export function TransactionsTable({
  direction,
  currency,
  transactions,
  sorting,
  onSortChange,
  onRowClick,
  error,
  isLoading = false,
  fetchNextPage,
  hasNextPage = false,
  isFetchingNextPage = false,
  sx,
}: Props) {
  const { tt } = useTT();
  const rowSettings = useCategoryTransactionRowSettings({
    direction,
    currency,
  });

  const sortingArray = useMemo(
    () => [
      {
        sortingAttribute: sorting.sortingAttribute,
        order: sorting.order,
      },
    ],
    [sorting.sortingAttribute, sorting.order],
  );

  if (error) {
    return (
      <Stack
        role="alert"
        sx={{
          ...BORDERED_CONTAINER_SX,
          alignItems: "center",
          justifyContent: "center",
          py: 6,
          px: 14,
          gap: 1,
          textAlign: "center",
          ...sx,
        }}
      >
        <Typography variant="h2" sx={{ color: "error.main" }}>
          {tt("categoryDetail.transactionsTable.error.title")}
        </Typography>
        <Typography variant="body2" sx={{ color: "text.secondary" }}>
          {tt("categoryDetail.transactionsTable.error.subtitle")}
        </Typography>
      </Stack>
    );
  }

  // Empty state: render outside the table, centered in a bordered flex container
  if (!isLoading && transactions.length === 0) {
    return (
      <Box sx={{ ...BORDERED_CONTAINER_SX, display: "flex", ...sx }}>
        <TransactionsTableEmptyState />
      </Box>
    );
  }

  // When loading with no data yet, show skeleton rows inside table body.
  // Wrapped in TableRow/TableCell with full colspan so it spans the entire table width.
  // We pass isLoading={false} when empty to avoid its built-in "Loading..." text;
  // for non-empty rows, isLoading is passed through to show the standard bar + fade overlay.
  const noDataContent =
    isLoading && transactions.length === 0 ? (
      <TableRow>
        <TableCell
          colSpan={rowSettings.columns.length}
          sx={{ p: 0, border: 0 }}
        >
          <LoadingMoreSkeleton />
        </TableCell>
      </TableRow>
    ) : undefined;

  const tableElement = (
    <DocumentListTable<CategoryTransaction>
      isLoading={isLoading && transactions.length > 0}
      rowSettings={rowSettings}
      rows={transactions as Array<CategoryTransaction>}
      totalRowCount={transactions.length}
      showHeader
      showPagination={false}
      sorting={sortingArray}
      onSortChange={onSortChange}
      onRowClick={onRowClick}
      noDataContent={noDataContent}
    />
  );

  // Scrollable Box wraps InfiniteList so the sentinel is inside the scroll area
  return (
    <Box sx={{ ...TABLE_WRAPPER_SX, ...sx }}>
      {fetchNextPage != null ? (
        <InfiniteList
          fetchNextPage={fetchNextPage}
          hasNextPage={hasNextPage}
          isFetchingNextPage={isFetchingNextPage}
          isLoading={false}
          loader={<LoadingMoreSkeleton />}
        >
          {tableElement}
        </InfiniteList>
      ) : (
        tableElement
      )}
    </Box>
  );
}

