function getAmountColor(
  amount: number,
  direction: TransactionDirection,
): string {
  if (direction === "OUT") return "text.primary";
  if (amount === 0) return "text.primary";
  return amount > 0 ? "success.main" : "error.main";
}

type Props = {
  transaction: CategoryTransaction;
  currency: string;
  direction: TransactionDirection;
};

export function ColumnAmount({ transaction, currency, direction }: Props) {
  return (
    <Typography
      variant="body2"
      sx={{
        fontWeight: 600,
        color: getAmountColor(transaction.amount, direction),
      }}
    >
      <CurrencyAmount
        value={transaction.amount}
        currency={currency}
        signDisplay="always"
      />
    </Typography>
  );
}

