        }
      > */}
      <Stack sx={{ py: 3, gap: 2, height: "80vh", overflow: "hidden" }}>
        {/* Title */}
        <Typography variant="body1" component="h2" id="category-detail-title">
          <Typography component="span" sx={{ fontWeight: 700 }}>
            {categoryLabel}
          </Typography>{" "}
          {tt("categoryDetail.transactions")} {periodLabel}
        </Typography>

        {/* Progress card: Paid / Expected / Difference */}
        <ProgressCard
