          currency={currency}
          paid={paid}
          forecasted={forecasted}
        />

        <Stack
          sx={{
            gap: 2,
            flex: 1,
            minHeight: 0,
          }}
        >
          {/* Tabs + action */}
          <Stack
            sx={{
              flexDirection: "row",
              justifyContent: "space-between",
              alignItems: "center",
            }}
          >
            <Tabs
              value="paid"
              // onChange={(_event, value: string) => setActiveTab(value)}
              aria-label={tt("categoryDetail.accessibility.transactionTabs")}
              sx={{ minHeight: "unset" }}
            >
              <Tab label={tt("categoryDetail.tabs.paid")} value="paid" />
            </Tabs>
          </Stack>

