import { useCallback, useRef } from "react";
import { useLocalStorage, useSessionStorage } from "react-use";

import type { CategoryFilter } from "../cashflow-table/types/index.ts";
import type { Currency, Interval } from "../types/index.ts";

export type CompanySettings = {
  categoryFilter?: CategoryFilter;
  currency?: Currency;
};

type SelectedPeriod = {
  selectedDay: string;
  interval: Interval;
};

export const STORAGE_KEYS = {
  COMPANY_SETTINGS: "cashflow-company-settings",
  SELECTED_PERIOD: "cashflow-selected-period",
} as const;

export function useCompanySettingsStore<D extends Partial<CompanySettings>>(
  companyId: string,
  defaultValue: D,
): readonly [CompanySettings & D, (newValue: Partial<CompanySettings>) => void];
export function useCompanySettingsStore(
  companyId: string,
): readonly [
  CompanySettings | undefined,
  (newValue: Partial<CompanySettings>) => void,
];
export function useCompanySettingsStore(
  companyId: string,
  defaultValue?: CompanySettings,
) {
  const [allData, setAllData] = useLocalStorage<
    Record<string, CompanySettings>
  >(STORAGE_KEYS.COMPANY_SETTINGS, {});

  // react-use's setter does not support functional updater form correctly
  // (likely resolves prev from stale closure), so use a ref for latest data
  const allDataRef = useRef(allData);
  allDataRef.current = allData;

  const update = useCallback(
    (newValue: Partial<CompanySettings>) => {
      setAllData({
        ...allDataRef.current,
        [companyId]: { ...allDataRef.current?.[companyId], ...newValue },
      });
    },
    [companyId, setAllData],
  );

  const value = defaultValue
    ? { ...defaultValue, ...allData?.[companyId] }
    : allData?.[companyId];

  return [value, update] as const;
}

export function useSelectedPeriodStore(
  companyId: string,
): [SelectedPeriod | undefined, (newValue: Partial<SelectedPeriod>) => void] {
  const [allData, setAllData] = useSessionStorage<
    Record<string, SelectedPeriod>
  >(STORAGE_KEYS.SELECTED_PERIOD, {});

  // for some reason session storage does not provide set callback with previous data
  // so we must hold a reference to the value, to prevent update loops
  const allDataRef = useRef(allData);
  allDataRef.current = allData;

  const update = useCallback(
    (newValue: Partial<SelectedPeriod>) => {
      setAllData({
        ...allDataRef.current,
        [companyId]: {
          ...allDataRef.current?.[companyId],
          ...newValue,
        } as SelectedPeriod,
      });
    },
    [companyId, setAllData],
  );

  return [allData[companyId], update] as const;
}

import { type ReactNode, useCallback, useMemo, useState } from "react";

import { createCheckedContext } from "@dfp/react-utils";

import {
  type CompanySettings,
  useCompanySettingsStore,
} from "./utils/index.ts";

export type CustomizeDialogTab = "currency" | "bankAccounts" | "health";

type CockpitContextType = {
  isOpen: boolean;
  activeTab: CustomizeDialogTab;
  companyId: string;
  companySettings: CompanySettings | undefined;
  updateCompanySettings: (newValue: Partial<CompanySettings>) => void;
  openDialog: (tab?: CustomizeDialogTab) => void;
  closeDialog: () => void;
  setActiveTab: (tab: CustomizeDialogTab) => void;
};

const [CockpitContextProvider, useCockpit] =
  createCheckedContext<CockpitContextType>("CockpitContext");

type CockpitProviderProps = {
  children: ReactNode;
  companyId: string;
};

export function CockpitProvider({ children, companyId }: CockpitProviderProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [activeTab, setActiveTab] =
    useState<CustomizeDialogTab>("bankAccounts");
  const [companySettings, updateCompanySettings] =
    useCompanySettingsStore(companyId);

  const openDialog = useCallback((tab?: CustomizeDialogTab) => {
    if (tab) {
      setActiveTab(tab);
    }
    setIsOpen(true);
  }, []);

  const closeDialog = useCallback(() => {
    setIsOpen(false);
    // reset active tab state
    setActiveTab("bankAccounts");
  }, []);

  const value = useMemo<CockpitContextType>(
    () => ({
      isOpen,
      activeTab,
      companyId,
      companySettings,
      updateCompanySettings,
      openDialog,
      closeDialog,
      setActiveTab,
    }),
    [
      isOpen,
      activeTab,
      companyId,
      companySettings,
      updateCompanySettings,
      openDialog,
      closeDialog,
    ],
  );

  return (
    <CockpitContextProvider value={value}>{children}</CockpitContextProvider>
  );
}

