// Defined in a separate file with no runtime project dependencies so that
// Vite HMR never re-evaluates this module when sibling files change.
// Both the Provider and useCashflowChartContext always reference the same
// context object, preventing the "outside Provider scope" error on hot-reload.
export const CashflowChartContext = createContext<
  CashflowChartContextType | undefined
>(undefined);

export function useCashflowChartContext(): CashflowChartContextType {
  const value = useContext(CashflowChartContext);
  if (value === undefined) {
    throw new Error(
      "Cannot access context value outside of its Provider scope (CashflowChartContext)",
    );
  }
  return value;
}

