  const { legendData } = useCashflowChartContext();
  const { openDialog } = useCockpit();
  const { currentBalance, currency, bankAccountCount, balanceQuality } =
    legendData;
  return (
    <Stack
      sx={{
        flexDirection: "row",
        alignItems: "center",
        gap: 1,
      }}
    >
      <CashflowQualityIndicator balanceQuality={balanceQuality} />
      {currentBalance !== null && (
        <Typography variant="h2">
          <CurrencyAmount
            value={currentBalance}
            currency={currency}
            superscriptDecimals
          />
        </Typography>
      )}
      <Dot color="custom.fillSecondaryActive" />
      <Link
        component="button"
        onClick={() => {
          openDialog("bankAccounts");
        }}
        sx={{
          display: "flex",
          alignItems: "center",
          gap: 0.5,
          color: "text.primary",
          textDecoration: "underline",
          cursor: "pointer",
        }}
      >
        {tt("chart.bankAccounts", { count: bankAccountCount })}
        <IconEdit05 />
      </Link>
    </Stack>
  );
}

import { Stack } from "@mui/material";

import { ChartLegendContent, type ChartLegendPayload } from "@dfp/react-chart";

import { CashflowBalanceSummary } from "./CashflowBalanceSummary.tsx";

type CashflowLegendProps = {
  payload: readonly ChartLegendPayload[];
};

export function CashflowLegend({ payload }: CashflowLegendProps) {
  return (
    <Stack
      sx={{
        flexDirection: "row",
        justifyContent: "space-between",
        mb: 2,
        mx: 2,
      }}
    >
      <CashflowBalanceSummary />
      <ChartLegendContent payload={getUniqueEntryByValue(payload)} />
    </Stack>
  );
}

function getUniqueEntryByValue(payload: readonly ChartLegendPayload[]) {
  const unique = new Map<string, ChartLegendPayload>();

  payload.forEach((entry) => {
    const exists = unique.has(entry.value ?? "");
    if (!exists) {
      unique.set(entry.value ?? "", entry);
    }
  });

  return Array.from(unique.values());
}

import { Box } from "@mui/material";

import { CashflowBarChart } from "../bar-chart/index.ts";
import { CashflowLineChart } from "../line-chart/index.ts";
import { useCashflowChartContext } from "./CashflowChartContext.tsx";

export function CashflowCharts() {
  const { viewMode } = useCashflowChartContext();

  return (
    <Box sx={{ width: "100%" }}>
      {viewMode === "bar" && <CashflowBarChart />}
      {viewMode === "line" && <CashflowLineChart />}
    </Box>
  );
}

