import { type CustomizeDialogTab, useCockpit } from "./CockpitContext.tsx";
import { CustomizeAccountsTab } from "./customize-accounts-tab/index.ts";
import { CustomizeCurrencyTab } from "./customizeCurrencyTab/index.ts";
import { customizeDialogFormOptions } from "./customizeDialogFormOptions.ts";
import { getSelectedAccounts } from "./utils/index.ts";

/**
 * Button that triggers the customize dialog.
 * Must be used within a CustomizeDialogProvider.
 */
export function CockpitCustomizeButton() {
  const { tt } = useTT();
  const { openDialog } = useCockpit();
  const { hasFeature } = useFeatureGuard();
  const canSelectBankAccount = hasFeature("bankAccounts", "selectBankAccount");

  if (!canSelectBankAccount) {
    return null;
  }

  return (
    <Button startIcon={<IconSettings04 />} onClick={() => openDialog()}>
      {tt("customize")}
    </Button>
  );
}

export function CockpitCustomizeDialog() {
  const { tt } = useTT();
  const {
    isOpen,
    activeTab,
    companyId,
    companySettings,
    updateCompanySettings,
    closeDialog,
    setActiveTab,
  } = useCockpit();
  const { showSnackbar } = useSnackbar();

  const { data: cashflowSettings } = useGetClientSettings({
    companyId,
    options: { select: getSelectedAccounts },
  });

  const { mutateAsync: updateSelectedAccounts } = useUpdateSelectedAccounts({
    companyId,
  });

  const handleCloseDialog = () => {
    form.reset();
    closeDialog();
  };

  const form = useAppForm({
    ...customizeDialogFormOptions,
    defaultValues: {
      selectedAccountIds: cashflowSettings?.accountIds ?? [],
      currencySettings:
        companySettings?.currency ?? cashflowSettings?.currency ?? "CZK",
    },
    onSubmit: async ({ value }) => {
      if (!cashflowSettings?.meta?.documentId) {
        throw new Error(tt("customizeDialog.noDocumentError"));
      }

      await updateSelectedAccounts({
        selectedAccountIds: value.selectedAccountIds,
        documentId: cashflowSettings.meta.documentId,
      });
      updateCompanySettings({
        currency: value.currencySettings,
      });

      showSnackbar({
        message: tt("customizeDialog.settingsSaved"),
        severity: "success",
      });
      handleCloseDialog();
    },
  });

  const formError = useStore(
    form.store,
    (state) => state.errorMap.onSubmit ?? {},
  );

  return (
    <AppDialog open={isOpen} onClose={handleCloseDialog}>
      <AppDialogHeader>{tt("customizeDialog.title")}</AppDialogHeader>
      <AppDialogContent>
        <form.AppForm>
          <TabContext value={activeTab}>
            <TabList
              onChange={(_, newValue: string) =>
                setActiveTab(newValue as CustomizeDialogTab)
              }
              aria-label={tt("customizeDialog.title")}
            >
              <Tab
                value="currency"
                label={tt("customizeDialog.tabs.currency")}
              />
              <Tab
                value="bankAccounts"
                label={
                  <Stack sx={{ flexDirection: "row", gap: 1 }}>
                    {tt("customizeDialog.tabs.bankAccounts")}
                    <Chip label={cashflowSettings?.accountIds?.length ?? 0} />
                  </Stack>
                }
              />
              <Tab
                disabled
                value="health"
                label={tt("customizeDialog.tabs.health")}
              />
            </TabList>

            <Divider />

            {/* Keep the tabs mounted to preserve state on tab change (global save button) */}
            <TabPanel value="currency" keepMounted>
              <CustomizeCurrencyTab
                form={form}
                defaultCurrency={cashflowSettings?.currency ?? "CZK"}
              />
            </TabPanel>
            <TabPanel value="bankAccounts" sx={{ px: 0 }} keepMounted>
              <CustomizeAccountsTab form={form} companyId={companyId} />
            </TabPanel>
            <TabPanel value="health" keepMounted>
              <Typography variant="body1">
                {tt("customizeDialog.tabs.health")}
              </Typography>
            </TabPanel>
          </TabContext>
        </form.AppForm>
      </AppDialogContent>
      <AppDialogActions>
        <form.Subscribe
          selector={(state) => [state.isSubmitting, state.canSubmit]}
        >
          {([isSubmitting, canSubmit]) => (
            <Button
              variant="contained"
              color="primary"
              fullWidth
              disabled={!canSubmit}
              onClick={() => form.handleSubmit()}
              startIcon={isSubmitting ? <CircleLoading /> : undefined}
            >
              {tt("customizeDialog.save")}
            </Button>
          )}
        </form.Subscribe>
      </AppDialogActions>
      {Object.values(formError).map((errors) => {
        const firstErr = errors.at(0);
        return firstErr ? (
          <Box sx={{ mx: 4, mb: 4 }} key={firstErr.message}>
            <Alert severity="error">
              {tt(firstErr.message as Parameters<typeof tt>[0])}
            </Alert>
          </Box>
        ) : null;
      })}
    </AppDialog>
  );
}

