import { Box, Stack } from "@mui/material";
import dayjs from "dayjs";
import { useMemo } from "react";

import { useGetClientSettings } from "@dfp/bw-react-client-settings";
import { EmptyState } from "@dfp/react-components";
import { IconAlertCircle, IconBarChart03 } from "@dfp/react-icons";

import { useGetCashFlowAndBalanceStates } from "../queries/index.ts";
import { useTT } from "../useTT.ts";
import { CashflowTableSection } from "./CashflowTableSection.tsx";
import { useCockpit } from "./CockpitContext.tsx";
import { CurrentBalanceChartSection } from "./CurrentBalanceChartSection.tsx";
import { HealthIndicatorsSection } from "./HealthIndicatorsSection.tsx";
import { SelectionProvider } from "./SelectionContext.tsx";
import { TimePeriodProvider } from "./TimePeriodContext.tsx";
import { cashflowLayoutConfig } from "./cashflow-layout.config.ts";
import { CashflowTableProvider } from "./cashflow-table/index.ts";
import { CashflowChartProvider } from "./chart/index.ts";
import {
  useCashflowLayoutConfig,
  useCashflowTimePeriodFilter,
  useCategoryFilter,
} from "./hooks/index.ts";
import type { Currency } from "./types/index.ts";
import {
  findColumnIndexForDate,
  getClientSettings,
  mapCategoryFilterToParam,
} from "./utils/index.ts";

type CashflowTabProps = {
  companyId: string;
};

export function CashflowTab({ companyId }: CashflowTabProps) {
  const { tt } = useTT();
  const { companySettings } = useCockpit();
  const clientSettings = useGetClientSettings({
    companyId,
    options: { select: getClientSettings },
  });
  const currency: Currency =
